import os

LOGIN_PAGE = "\"use client\";\n\nimport { useState } from \"react\";\nimport { useRouter } from \"next/navigation\";\nimport { createClient } from \"@/lib/supabase/client\";\n\nexport default function LoginPage() {\n  const router = useRouter();\n  const supabase = createClient();\n\n  const [email, setEmail] = useState(\"\");\n  const [password, setPassword] = useState(\"\");\n  const [error, setError] = useState<string | null>(null);\n  const [loading, setLoading] = useState(false);\n\n  const handleSignIn = async (e: React.FormEvent) => {\n    e.preventDefault();\n    setError(null);\n    setLoading(true);\n\n    const { error } = await supabase.auth.signInWithPassword({\n      email,\n      password,\n    });\n\n    setLoading(false);\n\n    if (error) {\n      setError(error.message);\n      return;\n    }\n\n    router.push(\"/dashboard\");\n    router.refresh();\n  };\n\n  return (\n    <main className=\"flex min-h-screen items-center justify-center bg-brand-gray px-4\">\n      <div className=\"w-full max-w-md rounded-xl bg-brand-maroon p-10 shadow-2xl\">\n        <div className=\"flex flex-col items-center\">\n          <div className=\"mb-4 flex h-16 w-16 items-center justify-center rounded-xl bg-white p-2\">\n            <img\n              src=\"/logo.png\"\n              alt=\"Hendrickson\"\n              className=\"h-full w-full object-contain\"\n            />\n          </div>\n          <h1 className=\"text-2xl font-bold text-white\">Hendrickson</h1>\n          <p className=\"mt-1 text-sm text-white/70\">Sign in to your account</p>\n        </div>\n\n        <form onSubmit={handleSignIn} className=\"mt-8 space-y-5\">\n          <div>\n            <label\n              htmlFor=\"email\"\n              className=\"mb-1 block text-xs font-semibold uppercase tracking-wide text-white\"\n            >\n              Email address\n            </label>\n            <input\n              id=\"email\"\n              type=\"email\"\n              required\n              value={email}\n              onChange={(e) => setEmail(e.target.value)}\n              placeholder=\"you@example.com\"\n              className=\"w-full rounded-md border border-black/10 bg-white px-4 py-2 text-black placeholder:text-black/40 focus:border-black focus:outline-none focus:ring-1 focus:ring-black\"\n            />\n          </div>\n\n          <div>\n            <label\n              htmlFor=\"password\"\n              className=\"mb-1 block text-xs font-semibold uppercase tracking-wide text-white\"\n            >\n              Password\n            </label>\n            <input\n              id=\"password\"\n              type=\"password\"\n              required\n              value={password}\n              onChange={(e) => setPassword(e.target.value)}\n              placeholder=\"••••••••\"\n              className=\"w-full rounded-md border border-black/10 bg-white px-4 py-2 text-black placeholder:text-black/40 focus:border-black focus:outline-none focus:ring-1 focus:ring-black\"\n            />\n          </div>\n\n          {error && (\n            <p className=\"rounded-md bg-white px-3 py-2 text-sm text-brand-maroon\">\n              {error}\n            </p>\n          )}\n\n          <button\n            type=\"submit\"\n            disabled={loading}\n            className=\"w-full rounded-md bg-black py-2.5 font-semibold text-white transition hover:bg-black/80 disabled:opacity-60\"\n          >\n            {loading ? \"Signing in...\" : \"Sign In\"}\n          </button>\n        </form>\n      </div>\n    </main>\n  );\n}\n"

DASHBOARD_PAGE = "import { createClient } from \"@/lib/supabase/server\";\nimport SignOutButton from \"./sign-out-button\";\n\nexport default async function DashboardPage() {\n  const supabase = await createClient();\n  const {\n    data: { user },\n  } = await supabase.auth.getUser();\n\n  return (\n    <div className=\"min-h-screen bg-brand-gray\">\n      <header className=\"flex items-center justify-between bg-brand-black px-6 py-4\">\n        <div className=\"flex items-center gap-3\">\n          <div className=\"flex h-8 w-8 items-center justify-center rounded-md bg-white p-1\">\n            <img\n              src=\"/logo.png\"\n              alt=\"Hendrickson\"\n              className=\"h-full w-full object-contain\"\n            />\n          </div>\n          <span className=\"text-lg font-bold text-white\">Hendrickson</span>\n        </div>\n        <div className=\"flex items-center gap-4\">\n          <span className=\"text-sm text-white/70\">{user?.email}</span>\n          <SignOutButton />\n        </div>\n      </header>\n\n      <main className=\"p-8\">\n        <h1 className=\"text-2xl font-bold text-brand-maroon\">Dashboard</h1>\n        <p className=\"mt-1 text-black/60\">Welcome back, {user?.email}</p>\n      </main>\n    </div>\n  );\n}\n"

def write_file(path, content):
    d = os.path.dirname(path)
    if d:
        os.makedirs(d, exist_ok=True)
    with open(path, "w") as f:
        f.write(content)
    print(f"Wrote {path}")

write_file("app/login/page.tsx", LOGIN_PAGE)
write_file("app/dashboard/page.tsx", DASHBOARD_PAGE)
print("Done with code files. Now add public/logo.png separately (see instructions).")
